// Extract uploaded files from webhook
const body = $input.item.json.body;

return {
  json: {
    dos_file: body.dos_file || null,
    previous_pjb_file: body.previous_pjb_file || null,
    lessons_learned: body.lessons_learned || null,
    well_name: body.well_name || '',
    rig_name: body.rig_name || '',
    customer: body.customer || '',
    timestamp: new Date().toISOString()
  }
};

values.content:
=Generate a Pre-Job Brief from the following documents:

**DOS (Daily Operations Summary):**
{{ $json.dos_file }}

**Previous PJB (if provided):**
{{ $json.previous_pjb_file }}

**Lessons Learned (if provided):**
{{ $json.lessons_learned }}

**Well Information:**
- Well Name: {{ $json.well_name }}
- Rig Name: {{ $json.rig_name }}
- Customer: {{ $json.customer }}

Please extract and structure the information into a complete PJB document.

parameters.jsCode:
// Parse AI response and structure PJB data
const aiResponse = $input.item.json;
const wellInfo = $('Extract Files').item.json;

let pjbContent;
try {
  // Try to parse if AI returned JSON
  pjbContent = typeof aiResponse.response === 'string' 
    ? JSON.parse(aiResponse.response)
    : aiResponse.response;
} catch {
  // If not JSON, structure the text response
  pjbContent = {
    raw_text: aiResponse.response || aiResponse.message?.content || 'No response'
  };
}

return {
  json: {
    well_name: wellInfo.well_name,
    rig_name: wellInfo.rig_name,
    customer: wellInfo.customer,
    date: new Date().toLocaleDateString('en-US'),
    timestamp: wellInfo.timestamp,
    pjb_content: pjbContent,
    well_objective: pjbContent.well_objective || 'Not extracted',
    bha_overview: pjbContent.bha_overview || 'Not extracted',
    dap: pjbContent.daily_activity_plan || pjbContent.dap || 'Not extracted',
    value_moments: pjbContent.value_moments || 'Not extracted',
    safety_moments: pjbContent.safety_moments || 'Not extracted',
    recent_incidents: pjbContent.recent_incidents || pjbContent.lessons_learned || 'Not extracted',
    full_text: pjbContent.raw_text || JSON.stringify(pjbContent, null, 2)
  }
};

